function saveUsers() {
  try { localStorage.setItem('qolda_users', JSON.stringify(USERS)); } catch(e) {}
}
function loadUsers() {
  try {
    const raw = localStorage.getItem('qolda_users');
    if (raw) return JSON.parse(raw);
  } catch(e) {}
  return [];
}
function saveSession(user) {
  try {
    localStorage.setItem('qolda_session', JSON.stringify(user));
    localStorage.setItem('qolda_session_id', String(user.id));
  } catch(e) {}
}
function clearSession() {
  try {
    localStorage.removeItem('qolda_session');
    localStorage.removeItem('qolda_session_id');
  } catch(e) {}
}
function loadSession() {
  try {
    const raw = localStorage.getItem('qolda_session');
    if (raw) return JSON.parse(raw);
  } catch(e) {}
  return null;
}

let USERS = loadUsers();
let SESSION = null;
let LANG = 'kk';
let CHAT_HISTORY = [];

// Auto-login: run immediately, no need to wait for DOMContentLoaded
// since this script is at end of <body> — DOM is already ready
function _startApp() {
  const saved = loadSession();
  if (saved) {
    // Re-fetch freshest user data from USERS store (in case profile was updated)
    const found = USERS.find(u => u.id === saved.id && u.passHash === saved.passHash);
    if (found) {
      SESSION = found;
      LANG = found.lang || 'kk';
      renderDashboard(found);
      return;
    }
    // Session exists but user not in store — clear stale session
    clearSession();
  }
  renderAuth();
}

// _startApp() called at bottom of script
 
function t(key, ...args) {
const val = T[LANG][key];
if (typeof val === 'function') return val(...args);
return val || key;
}
function hashPass(p) {
let h = 0;
for (let i = 0; i < p.length; i++) h = (Math.imul(31, h) + p.charCodeAt(i)) | 0;
return h.toString(36);
}
function fireToast(msg, type='success') {
const el = document.getElementById('toast');
const colors = { success:'var(--g1)', error:'#f87171', info:'#93c5fd' };
el.style.background = colors[type]||'var(--g1)';
el.textContent = msg;
el.classList.remove('hidden');
clearTimeout(window._toastTimer);
window._toastTimer = setTimeout(()=>el.classList.add('hidden'), 3000);
}

