// Track which tasks have already shown their notification this session
const _snShownTasks = new Set();

function showSupportNotif(taskIdx) {
// Only show once per task — no repeat on re-check
if (_snShownTasks.has(taskIdx)) return;
_snShownTasks.add(taskIdx);

const lang = (typeof LANG !== 'undefined' && SUPPORT_MSGS[LANG]) ? LANG : 'kk';
const msgs = SUPPORT_MSGS[lang];
// Fixed: task 0 → msg[0], task 1 → msg[1], etc.
const msg = msgs[taskIdx % msgs.length];

const existing = document.getElementById('support-notif');
if (existing) { existing.remove(); clearTimeout(window._snTimer); clearTimeout(window._snHideTimer); }

const notif = document.createElement('div');
notif.id = 'support-notif';

const iconEl = document.createElement('div');
iconEl.className = 'sn-icon';
const emojiMatch = msg.match(/^(\p{Emoji_Presentation}|\p{Extended_Pictographic})+/u);
iconEl.textContent = emojiMatch ? emojiMatch[0] : '🌸';

const textEl = document.createElement('div');
textEl.className = 'sn-text';
textEl.textContent = msg.replace(/^(\p{Emoji_Presentation}|\p{Extended_Pictographic})+\s*/u, '');

const bar = document.createElement('div');
bar.className = 'sn-bar';
bar.style.width = '100%';

notif.appendChild(iconEl);
notif.appendChild(textEl);
notif.appendChild(bar);
document.body.appendChild(notif);

const DURATION = 3800;
requestAnimationFrame(() => {
  requestAnimationFrame(() => {
    bar.style.transition = 'width ' + DURATION + 'ms linear';
    bar.style.width = '0%';
  });
});

window._snHideTimer = setTimeout(() => {
  notif.classList.add('hiding');
  window._snTimer = setTimeout(() => { if (notif.parentNode) notif.remove(); }, 340);
}, DURATION);
}
 
function el(tag, attrs, ...children) {
const e = document.createElement(tag);
if (attrs) for (const [k,v] of Object.entries(attrs)) {
if (k==='style'&&typeof v==='object') Object.assign(e.style,v);
else if (k.startsWith('on')) e.addEventListener(k.slice(2).toLowerCase(),v);
else if (k==='className') e.className=v;
else e.setAttribute(k,v);
}
for (const c of children) {
if (c===null||c===undefined) continue;
if (typeof c==='string') e.appendChild(document.createTextNode(c));
else if (c instanceof Node) e.appendChild(c);
}
return e;
}
function div(a,...c){ return el('div',a,...c); }
function span(a,...c){ return el('span',a,...c); }
function btn(a,...c){ return el('button',a,...c); }
function inp(a){ return el('input',a); }
function sel(a,opts,val){
const s=el('select',a);
for(const o of opts){
const opt=el('option',{value:o},o);
if(o===val) opt.selected=true;
s.appendChild(opt);
}
return s;
}
function field(labelTxt, type, id, placeholder){
const wrap=div({style:{marginBottom:'14px'}});
const lbl=el('label',{className:'lbl',for:id},labelTxt);
const input=inp({type:type||'text',id,placeholder:placeholder||'',className:'inp'});
if(type==='password'){
const row=div({style:{position:'relative'}});
const eye=span({style:{position:'absolute',right:'12px',top:'50%',transform:'translateY(-50%)',cursor:'pointer',fontSize:'16px',color:'var(--text3)'}},'👁');
let shown=false;
eye.onclick=()=>{shown=!shown;input.type=shown?'text':'password';eye.textContent=shown?'🙈':'👁';};
row.appendChild(input);row.appendChild(eye);
wrap.appendChild(lbl);wrap.appendChild(row);
} else { wrap.appendChild(lbl);wrap.appendChild(input); }
const errEl=div({className:'errtxt',style:{display:'none'}});
wrap.appendChild(errEl);
return {wrap,input,errEl};
}
function showErr(f,msg){f.input.classList.add('err');f.errEl.textContent=msg;f.errEl.style.display='block';}
function clearErr(f){f.input.classList.remove('err');f.errEl.style.display='none';}
function langSwitcher(onchange) {
const wrap = div({style:{display:'flex',gap:'6px',alignItems:'center'}});
['kk','ru','en'].forEach(lang=>{
const b = btn({className:'lang-btn'+(LANG===lang?' active':'')}, T[lang]['lang'+lang.charAt(0).toUpperCase()+lang.slice(1)]);
b.onclick=()=>{ LANG=lang; if(onchange) onchange(lang); };
wrap.appendChild(b);
});
return wrap;
}
 
function simpleMarkdown(text) {
if (!text) return '';
return text
.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
.replace(/\*\*(.*?)\*\*/g,'<strong>$1</strong>')
.replace(/## (.*?)(\n|$)/g,'<div style="font-weight:800;font-size:15px;margin:10px 0 4px;color:var(--g1)">$1</div>')
.replace(/- (.*?)(\n|$)/g,'<div style="display:flex;gap:6px;margin:2px 0"><span style="color:var(--g2)">•</span><span>$1</span></div>')
.replace(/\n/g,'<br>');
}
 
