regLink.onclick=regTab.onclick; loginLink.onclick=loginTab.onclick;
loginBtn.onclick=()=>{
[fEmail,fPass].forEach(f=>clearErr(f));
let ok=true;
const email=fEmail.input.value.trim(), pass=fPass.input.value;
if(!email){showErr(fEmail,t('errRequired'));ok=false;}
if(!pass){showErr(fPass,t('errPass'));ok=false;}
if(!ok) return;
const user=USERS.find(u=>u.email===email&&u.passHash===hashPass(pass));
if(!user){showErr(fPass,t('errWrong'));return;}
SESSION=user; LANG=user.lang||'kk';
saveSession(user);
fireToast(t('toastLogin',user.name.split(' ')[0]));
setTimeout(()=>renderDashboard(user),600);
};
regBtn.onclick=()=>{
[fName,fREmail,fRPass,fRPass2].forEach(f=>clearErr(f));
let ok=true;
const name=fName.input.value.trim(), email=fREmail.input.value.trim();
const pass=fRPass.input.value, pass2=fRPass2.input.value;
if(!name){showErr(fName,t('errRequired'));ok=false;}
if(!email){showErr(fREmail,t('errEmail'));ok=false;}
else if(!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)){showErr(fREmail,LANG==='kk'?'Дұрыс email енгізіңіз (мысалы: name@mail.com)':LANG==='en'?'Enter a valid email (e.g. name@mail.com)':'Введите корректный email (например: name@mail.com)');ok=false;}
if(email&&/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)&&USERS.find(u=>u.email===email)){showErr(fREmail,t('errExists'));ok=false;}
if(pass.length<6){showErr(fRPass,t('errMin6'));ok=false;}
if(pass!==pass2){showErr(fRPass2,t('errMatch'));ok=false;}
if(!ok) return;
const selectedGrpBtn=disabilityGroupBtns.querySelector('button[data-selected="1"]');
const disabilityGroup=selectedGrpBtn?selectedGrpBtn.textContent:null;
const user={id:Date.now(),name,email,city:(citySelect.value===CITIES[CITIES.length-1]&&cityCustomInput.value.trim())?cityCustomInput.value.trim():citySelect.value,diag:diagSelect.value,disabilityGroup,lang:LANG,passHash:hashPass(pass),planDone:[],createdAt:new Date().toISOString()};
USERS.push(user); SESSION=user;
saveUsers(); saveSession(user);
fireToast(t('toastReg',user.name.split(' ')[0]));
setTimeout(()=>renderDashboard(user),700);
};
