function showTab(tab){
currentTab=tab; content.innerHTML='';
if(tab==='overview') renderOverview();
else if(tab==='plan') renderPlan();
else if(tab==='clinics_all') renderClinicsAll();
else if(tab==='gov_support') renderGovSupport();
else if(tab==='quota') renderGovSupport();
else if(tab==='benefits') renderGovSupport();
else if(tab==='inspire') renderInspire();
else if(tab==='games') renderGames();
else if(tab==='ai') renderAIChat();
else if(tab==='law') renderLaw();
else if(tab==='charity') renderCharity();
else if(tab==='profile') renderProfile();
}
 
function togglePlanItem(i){
const wasUndone=!(u.planDone||[]).includes(i);
const done=(u.planDone||[]).includes(i)?(u.planDone||[]).filter(x=>x!==i):[...(u.planDone||[]),i];
u={...u,planDone:done}; USERS=USERS.map(x=>x.id===u.id?u:x); SESSION=u;
saveUsers(); saveSession(u);
if(wasUndone) showSupportNotif(i);
showTab(currentTab);
}
 
function getClinicsCountForUser() {
if (!u || !u.city) return '—';
const city = u.city.toLowerCase();
// Hardcoded clinic counts per region (as specified)
const regionCounts = [
  { count: 6,  match: ['орал', 'уральск', 'oral', 'батыс қазақ', 'западно-казах', 'zko'] },
  { count: 5,  match: ['қостанай / костанай', 'қостанай', 'костанай', 'kostanay', 'kost'] },
  { count: 8,  match: ['павлодар', 'pavlodar'] },
  { count: 18, match: ['шымкент', 'shymkent', 'түркістан', 'туркестан', 'turkestan'] },
  { count: 8,  match: ['атырау', 'atyrau'] },
  { count: 2,  match: ['петропавл', 'petropavl', 'солтүстік', 'северо-казах', 'nko'] },
  { count: 1,  match: ['өскемен', 'усть-каменогорск', 'oskemen', 'vko'] },
  { count: 2,  match: ['тараз', 'taraz', 'жамбыл', 'zhambyl'] },
  { count: 5,  match: ['ақтау', 'актау', 'aktau', 'маңғыстау', 'мангистау', 'mangystau'] },
  { count: 8,  match: ['көкшетау', 'кокшетау', 'kokshetau', 'ақмола', 'акмола', 'akmola'] },
  { count: 7,  match: ['қарағанды', 'карагандин', 'karagand'] },
  { count: 31, match: ['алматы', 'almaty'] },
  { count: 8,  match: ['ақтөбе', 'актобе', 'aktobe'] },
  { count: 24, match: ['астана', 'astana'] },
  { count: 1,  match: ['қызылорда', 'кызылорда', 'kyzylorda'] },
];
for (const entry of regionCounts) {
  if (entry.match.some(m => city.includes(m))) return String(entry.count);
}
// "Басқа / Другое / Other" or unrecognized — show total across all regions
const total = Object.values(KZ_CLINICS).reduce((s, arr) => s + arr.length, 0);
return String(total);
}

