row.appendChild(div({style:{width:'38px',height:'38px',borderRadius:'10px',background:'linear-gradient(135deg,var(--g4),var(--g6))',display:'flex',alignItems:'center',justifyContent:'center',fontSize:'17px'}},item.icon));
