// medicusunion.kz link block
const medicusBlock=div({style:{marginTop:'14px',padding:'14px 18px',borderRadius:'16px',border:'1.5px solid var(--border)',background:'rgba(255,255,255,.88)',display:'flex',flexDirection:'column',gap:'4px'}});
