// ── GLOBAL AI ENGINE (shared by full chat + float bubble) ──
const AI_SYSTEM_PROMPT = `Ты — универсальный AI-помощник для сайта Qolda, который помогает родителям и семьям с детьми с ОВЗ в Казахстане.
Отвечай на любые вопросы пользователя прямо и понятно, как ChatGPT.
Не выводи JSON, reasoning_content или внутреннюю логику.
Отвечай только текстом, коротко и по делу.
НИКОГДА не используй таблицы (| col | col |) — только обычный текст, нумерованные или маркированные списки.
Если вопрос слишком общий — дай полезный совет или информацию по теме.
Отвечай на языке вопроса: казахский вопрос — казахский ответ, русский — русский, английский — английский.
Никогда не отказывай в ответе.`;

function buildGeminiContentsGlobal(msgs, sys){
const out = [
{role:'user', parts:[{text:sys}]},
{role:'model', parts:[{text:'Понял! Готов помочь.'}]},
];
msgs.forEach(m => {
const role = m.role === 'assistant' ? 'model' : 'user';
const last = out[out.length-1];
if(last && last.role === role){
last.parts[0].text += '\n' + m.content;
} else {
out.push({role, parts:[{text: m.content}]});
}
});
if(out[out.length-1].role !== 'user'){
out.push({role:'user', parts:[{text:'Продолжи.'}]});
}
return out;
}

async function callAIGlobal(messages){
const sys = AI_SYSTEM_PROMPT;
const BACKEND_URL = '/api/chat';
try{
const res = await fetch(BACKEND_URL, {
method: 'POST', headers: {'Content-Type':'application/json'},
body: JSON.stringify({messages})
});
if(res.ok){ const d = await res.json(); if(d.reply && d.reply.length > 3) return d.reply; }
}catch(e){}
const GEMINI_KEYS = [
'AIzaSyB8tZZUFGTQEDFBjFACCEfk4FMb-O5AvVs',
'AIzaSyC-9jPf8xNmVGFKCbMvQ1tNH3YBxs5DKGE',
];
for(const key of GEMINI_KEYS){
try{
const contents = buildGeminiContentsGlobal(messages, sys);
const res = await fetch(
`https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${key}`,
{method:'POST',headers:{'Content-Type':'application/json'},
body: JSON.stringify({contents,generationConfig:{maxOutputTokens:1200, temperature:0.7}})}
);
if(res.ok){
const d = await res.json();
const r = d?.candidates?.[0]?.content?.parts?.[0]?.text || '';
if(r.length > 3) return r;
}
}catch(e){}
}
try{
const contents = buildGeminiContentsGlobal(messages, sys);
const res = await fetch(
'https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=AIzaSyB8tZZUFGTQEDFBjFACCEfk4FMb-O5AvVs',
{method:'POST',headers:{'Content-Type':'application/json'},
body: JSON.stringify({contents, generationConfig:{maxOutputTokens:1200}})}
);
if(res.ok){
const d = await res.json();
const r = d?.candidates?.[0]?.content?.parts?.[0]?.text || '';
if(r.length > 3) return r;
}
}catch(e){}
try{
const last = messages[messages.length-1]?.content || '';
const p = encodeURIComponent(sys.slice(0,300) + '\n\nUser: ' + last + '\nAssistant:');
const res = await fetch(`https://text.pollinations.ai/${p}?model=openai&private=true`);
if(res.ok){ const r = (await res.text()).trim(); if(r.length > 3 && !r.startsWith('<!')) return r; }
}catch(e){}
try{
const res = await fetch('https://api.anthropic.com/v1/messages',{
method:'POST',
headers:{
'Content-Type':'application/json',
'x-api-key':'__ANTHROPIC_KEY__',
'anthropic-version':'2023-06-01',
'anthropic-dangerous-direct-browser-access':'true'
},
body: JSON.stringify({model:'claude-haiku-4-5-20251001',max_tokens:1024,system:sys,messages})
});
if(res.ok){
const d = await res.json();
const r = (d.content||[]).filter(b=>b.type==='text').map(b=>b.text).join('').trim();
if(r.length > 3) return r;
}
}catch(e){}
return null;
}

