// ── Helper to render a card grid ─────────────────────────────────────────────
function renderBenefitGrid(cardsArr, container){
  const grid=div({style:{display:'grid',gridTemplateColumns:'1fr 1fr',gap:'16px',marginBottom:'8px'}});
  cardsArr.forEach(card=>{
    const c=div({className:'card',style:{padding:'22px'}});
    const hdr=div({style:{display:'flex',alignItems:'center',gap:'10px',marginBottom:'14px'}});
    hdr.appendChild(div({style:{width:'44px',height:'44px',borderRadius:'12px',background:'linear-gradient(135deg,var(--g4),var(--g6))',display:'flex',alignItems:'center',justifyContent:'center',fontSize:'20px'}},card.icon));
    hdr.appendChild(div({style:{fontFamily:"'Inter',sans-serif",fontWeight:'800',fontSize:'15px'}},card.title));
    c.appendChild(hdr);
    const ul=el('ul',{style:{listStyle:'none',display:'flex',flexDirection:'column',gap:'7px'}});
    card.items.forEach(item=>{
      const li=el('li',{style:{display:'flex',gap:'8px',fontSize:'13px',color:'var(--text2)',lineHeight:'1.5'}});
      li.appendChild(span({style:{color:'var(--g2)',fontSize:'10px',marginTop:'5px',flexShrink:'0'}},'●'));
      li.appendChild(span({},item)); ul.appendChild(li);
    });
    c.appendChild(ul); grid.appendChild(c);
  });
  container.appendChild(grid);
}

